1	"use client";
2	
3	import { useState, useRef, useCallback, useEffect } from "react";
4	import { useRouter } from "next/navigation";
5	import Link from "next/link";
6	
7	const ACCEPTED_EXTENSIONS =
8	  ".txt,.md,.markdown,.pdf,.docx,.vtt,.jsonl,.mp3,.m4a,.wav,.webm,.ogg,.aac";
9	
10	/**
11	 * Read the duration of an audio File in the browser by mounting an
12	 * offscreen HTMLAudioElement and waiting for `loadedmetadata`. Returns
13	 * the duration in whole seconds, or rejects after a timeout / if the
14	 * browser can't decode the file. Used to pre-fill
15	 * `Upload.audioDurationSec` so published episodes show "— 47:12 —"
16	 * badges on the blog index.
17	 */
18	async function probeAudioDuration(file: File): Promise<number> {
19	  return new Promise((resolve, reject) => {
20	    const el = document.createElement("audio");
21	    const url = URL.createObjectURL(file);
22	    const timer = window.setTimeout(() => {
23	      cleanup();
24	      reject(new Error("duration probe timeout"));
25	    }, 6000);
26	    const cleanup = () => {
27	      window.clearTimeout(timer);
28	      URL.revokeObjectURL(url);
29	      el.src = "";
30	    };
31	    el.preload = "metadata";
32	    el.onloadedmetadata = () => {
33	      const d = el.duration;
34	      cleanup();
35	      if (!Number.isFinite(d) || d <= 0) {
36	        reject(new Error("invalid duration"));
37	      } else {
38	        resolve(Math.round(d));
39	      }
40	    };
41	    el.onerror = () => {
42	      cleanup();
43	      reject(new Error("audio load failed"));
44	    };
45	    el.src = url;
46	  });
47	}
48	
49	// ─────────────────────────────────────────────────────────────────────
50	// Queue model — one UploadItem per pending/in-flight/finished upload.
51	// ─────────────────────────────────────────────────────────────────────
52	//
53	// A dropped file becomes an UploadItem with phase="queued". On submit,
54	// we walk the queue sequentially: each item moves through preparing →
55	// uploading → finalizing → processing → ingested|failed. All items
56	// share the batch-level metadata below (description, visibility,
57	// publish-as-post, excerpt, byline). Per-item metadata (title,
58	// sourceType) is derived from the filename and MIME type by default;
59	// the user can edit them only in single-file mode to keep the bulk
60	// UI uncluttered.
61	
62	type ItemPhase =
63	  | "queued"      // in the queue, upload not yet started
64	  | "preparing"   // signed-flow only — calling /api/upload/signed/prepare
65	  | "uploading"   // bytes in flight (either inline POST or direct PUT)
66	  | "finalizing"  // signed-flow only — calling /finalize/[id]
67	  | "processing"  // upload accepted, awaiting Noosphere ingestion
68	  | "ingested"    // terminal: success
69	  | "failed";     // terminal: error
70	
71	interface UploadItem {
72	  id: string;           // local uuid for React keys
73	  file: File;
74	  title: string;
75	  sourceType: string;
76	  phase: ItemPhase;
77	  progressFrac: number; // 0..1 during "uploading" phase
78	  progressBytes?: string;
79	  uploadId?: string;    // server-assigned after prepare/inline
80	  claimsCount?: number;
81	  publicUrl?: string;
82	  errorMessage?: string;
83	  serverStatus?: string; // raw status string from /api/upload/:id
84	}
85	
86	function itemIsTerminal(p: ItemPhase): boolean {
87	  return p === "ingested" || p === "failed";
88	}
89	
90	function deriveTitleFromFilename(name: string): string {
91	  return name.replace(/\.[^/.]+$/, "").replace(/[-_]/g, " ");
92	}
93	
94	function deriveSourceTypeFromFile(f: File): string {
95	  if (f.type.startsWith("audio/")) return "audio";
96	  return "written";
97	}
98	
99	function isAudioFile(f: File): boolean {
100	  return (
101	    f.type.startsWith("audio/") ||
102	    /\.(mp3|m4a|wav|webm|ogg|aac)$/i.test(f.name)
103	  );
104	}
105	
106	/** Files ≤ this go through the single-POST inline flow; larger files
107	 *  take the three-step signed-URL flow that bypasses Vercel's 4.4 MB
108	 *  body cap. Audio ALWAYS takes signed so we have a persistent
109	 *  `audioUrl` for playback regardless of size. */
110	const INLINE_MAX = 3.5 * 1024 * 1024;
111	
112	/** Tight human bytes for the queue row — "84 KB", "12.3 MB". */
