161	 * Vercel-compat copy
162	 * ------------------
163	 * Earlier copy mentioned `python -m noosphere ingest`, which is only
164	 * true for self-hosted deploys. Neutral phrasing here; the scribe's
165	 * log (polled after submit) reports the real status.
166	 */
167	export default function UploadForm() {
168	  const router = useRouter();
169	  const fileRef = useRef<HTMLInputElement>(null);
