171	
172	  // ── Queue ──────────────────────────────────────────────────────
173	  const [items, setItems] = useState<UploadItem[]>([]);
174	  // Latest-ref pattern: the polling effect reads the current items
175	  // through this ref so it doesn't re-create intervals on every item
176	  // update (which happens many times per second during upload).
177	  const itemsRef = useRef(items);
178	  itemsRef.current = items;
179	
180	  // ── Shared metadata (all items in the batch) ───────────────────
181	  const [description, setDescription] = useState("");
182	  const [publishAsPost, setPublishAsPost] = useState(false);
183	  const [blogExcerpt, setBlogExcerpt] = useState("");
184	  const [authorBio, setAuthorBio] = useState("");
185	  // Three-way visibility ladder. At most one of the two flags below
186	  // is `true` at any moment (the mutual-exclusion is enforced in the
187	  // render block, by disabling whichever pair is incompatible with
188	  // the flag just flipped on). The *unchecked* default maps to
189	  // visibility="org" (firm-shared, publishable).
190	  const [privateUpload, setPrivateUpload] = useState(false);
191	  const [semiPrivateUpload, setSemiPrivateUpload] = useState(false);
192	
193	  // Single source of truth that the submit-side payload construction
194	  // reads. Keeps the two flags and the server string in lockstep.
195	  const visibility: "org" | "semi-private" | "private" = privateUpload
196	    ? "private"
197	    : semiPrivateUpload
198	      ? "semi-private"
199	      : "org";
200	
201	  // ── Top-level form state ───────────────────────────────────────
202	  const [uploading, setUploading] = useState(false);
203	  const [error, setError] = useState("");
204	  const [success, setSuccess] = useState("");
205	
206	  const updateItem = useCallback(
207	    (id: string, patch: Partial<UploadItem>) => {
208	      setItems((prev) =>
209	        prev.map((it) => (it.id === id ? { ...it, ...patch } : it)),
210	      );
211	    },
212	    [],
213	  );
214	
215	  const addFiles = useCallback(
216	    (files: FileList | File[]) => {
217	      const list = Array.from(files);
218	      if (list.length === 0) return;
219	      setItems((prev) => {
220	        // Dedupe by (name, size) against already-queued items so
221	        // dropping the same file twice doesn't create a duplicate row.
222	        const seen = new Set(
223	          prev.map((it) => `${it.file.name}|${it.file.size}`),
224	        );
225	        const additions: UploadItem[] = [];
226	        for (const f of list) {
227	          const key = `${f.name}|${f.size}`;
228	          if (seen.has(key)) continue;
229	          seen.add(key);
230	          additions.push({
231	            id:
232	              typeof crypto !== "undefined" && "randomUUID" in crypto
233	                ? crypto.randomUUID()
234	                : `${Date.now()}-${Math.random().toString(36).slice(2, 9)}`,
235	            file: f,
236	            title: deriveTitleFromFilename(f.name),
237	            sourceType: deriveSourceTypeFromFile(f),
238	            phase: "queued",
239	            progressFrac: 0,
240	          });
241	        }
242	        return additions.length === 0 ? prev : [...prev, ...additions];
243	      });
244	    },
245	    [],
246	  );
