269	  // ── Inline flow: one POST, bytes in request body (≤ 3.5 MB) ────
270	  async function runInline(item: UploadItem): Promise<string> {
271	    updateItem(item.id, { phase: "uploading", progressFrac: 0.1 });
272	    const fd = new FormData();
273	    fd.append("file", item.file);
274	    fd.append("title", item.title);
275	    fd.append("description", description);
276	    fd.append("sourceType", item.sourceType);
277	    fd.append("publishAsPost", publishAsPost ? "1" : "0");
278	    if (publishAsPost) {
279	      fd.append("blogExcerpt", blogExcerpt.trim());
280	      fd.append("authorBio", authorBio.trim());
281	    }
282	    fd.append("visibility", visibility);
283	
284	    const res = await fetch("/api/upload", { method: "POST", body: fd });
285	    const data = await res.json();
286	    if (!res.ok) {
287	      throw new Error(data.error || "Upload failed");
288	    }
289	    return data.id as string;
290	  }
291	
292	  // ── Signed flow: prepare → direct PUT to Supabase → finalize ───
293	  async function runSigned(
294	    item: UploadItem,
295	    opts: { isAudio: boolean },
296	  ): Promise<string> {
297	    const f = item.file;
298	    updateItem(item.id, { phase: "preparing", progressFrac: 0 });
299	
300	    const audioDurationSec = opts.isAudio
301	      ? await probeAudioDuration(f).catch(() => null)
302	      : null;
303	
304	    const prepareBody = {
305	      filename: f.name,
306	      mimeType:
307	        f.type || (opts.isAudio ? "audio/mpeg" : "application/octet-stream"),
308	      size: f.size,
309	      title: item.title,
310	      description,
311	      sourceType:
312	        item.sourceType || (opts.isAudio ? "audio" : "written"),
313	      visibility,
314	      publishAsPost,
315	      blogExcerpt: publishAsPost ? blogExcerpt.trim() : "",
316	      authorBio: publishAsPost ? authorBio.trim() : "",
317	      audioDurationSec,
318	    };
319	    const prep = await fetch("/api/upload/signed/prepare", {
320	      method: "POST",
321	      headers: { "Content-Type": "application/json" },
322	      body: JSON.stringify(prepareBody),
323	    });
324	    const prepData = await prep.json();
325	    if (!prep.ok) {
326	      throw new Error(prepData.error || `Prepare failed (${prep.status})`);
327	    }
328	    const { uploadId, signedUrl, headers: putHeaders } = prepData as {
329	      uploadId: string;
330	      signedUrl: string;
331	      headers?: Record<string, string>;
332	    };
333	
334	    const totalMB = (f.size / 1024 / 1024).toFixed(1);
335	    updateItem(item.id, {
336	      phase: "uploading",
337	      uploadId,
338	      progressFrac: 0,
339	      progressBytes: `0 MB / ${totalMB} MB`,
340	    });
341	
342	    await new Promise<void>((resolve, reject) => {
343	      const xhr = new XMLHttpRequest();
344	      xhr.open("PUT", signedUrl);
345	      const ct =
346	        (putHeaders && putHeaders["Content-Type"]) ||
347	        f.type ||
348	        "application/octet-stream";
349	      // Keep the PUT a "simple" CORS request: only `Content-Type`.
350	      // The signed URL carries the JWT as `?token=<jwt>`, so no
351	      // Authorization header is needed (and adding one would trigger
352	      // a preflight OPTIONS that doesn't always succeed).
353	      xhr.setRequestHeader("Content-Type", ct);
354	      xhr.upload.onprogress = (ev) => {
355	        if (ev.lengthComputable) {
356	          const frac = ev.loaded / ev.total;
357	          updateItem(item.id, {
358	            progressFrac: frac,
359	            progressBytes: `${(ev.loaded / 1024 / 1024).toFixed(1)} MB / ${totalMB} MB`,
360	          });
361	        }
362	      };
363	      xhr.onload = () => {
364	        if (xhr.status >= 200 && xhr.status < 300) {
365	          updateItem(item.id, { progressFrac: 1 });
366	          resolve();
367	        } else {
368	          reject(
369	            new Error(
370	              `Direct upload failed (${xhr.status}): ${(xhr.responseText || "").slice(0, 180)}`,
371	            ),
372	          );
373	        }
374	      };
375	      xhr.onerror = () =>
376	        reject(
377	          new Error(
378	            "Direct upload failed: network/CORS error. " +
379	              "Check Supabase bucket CORS + file-size limit.",
380	          ),
381	        );
382	      xhr.onabort = () =>
383	        reject(new Error("Upload aborted"));
384	      xhr.ontimeout = () =>
385	        reject(new Error("Upload timed out"));
386	      xhr.send(f);
387	    });
388	
389	    updateItem(item.id, { phase: "finalizing" });
390	    const fin = await fetch(`/api/upload/signed/finalize/${uploadId}`, {
391	      method: "POST",
392	      headers: { "Content-Type": "application/json" },
393	      body: JSON.stringify({ audioDurationSec }),
394	    });
395	    const finData = await fin.json();
396	    if (!fin.ok) {
397	      throw new Error(finData.error || `Finalize failed (${fin.status})`);
398	    }
399	    return uploadId;
400	  }
