402	  async function runOne(item: UploadItem): Promise<void> {
403	    try {
404	      const audio = isAudioFile(item.file);
405	      const useSigned = audio || item.file.size > INLINE_MAX;
406	      const uploadId = useSigned
407	        ? await runSigned(item, { isAudio: audio })
408	        : await runInline(item);
409	      updateItem(item.id, {
410	        phase: "processing",
411	        uploadId,
412	        progressFrac: 1,
413	      });
414	    } catch (err) {
415	      updateItem(item.id, {
416	        phase: "failed",
417	        errorMessage: err instanceof Error ? err.message : String(err),
418	      });
419	    }
420	  }
