422	  async function handleSubmit(e: React.FormEvent) {
423	    e.preventDefault();
424	    if (items.length === 0) {
425	      setError("Drop at least one file to upload.");
426	      return;
427	    }
428	    setError("");
429	    setSuccess("");
430	    setUploading(true);
431	
432	    // Sequential upload. For text-y files each takes ~1s, so even a
433	    // 20-file drop finishes the upload phase in well under a minute.
434	    // For audio / large files, sequential is what you want anyway —
435	    // parallel PUTs would just starve each other of bandwidth.
436	    const snapshot = items.slice();
437	    for (const item of snapshot) {
438	      if (itemIsTerminal(item.phase) || item.phase === "processing") continue;
439	      // Re-read the latest version from the queue in case the user
440	      // removed it mid-batch. (Harmless to skip missing rows.)
441	      const fresh = itemsRef.current.find((it) => it.id === item.id);
442	      if (!fresh) continue;
443	      await runOne(fresh);
444	    }
445	
446	    setSuccess(
447	      items.length > 1
448	        ? `All ${items.length} uploads received — awaiting Noosphere…`
449	        : "Upload received. Noosphere is processing in the cloud…",
450	    );
451	  }
