453	  // ── Status polling: drives "processing → ingested|failed" ──────
454	  //
455	  // Started when `uploading` flips to true; tears down when every
456	  // item has reached a terminal phase. Uses the latest-ref pattern
457	  // so it doesn't restart on every item update — the interval reads
458	  // `itemsRef.current` each tick.
459	  useEffect(() => {
460	    if (!uploading) return;
461	
462	    const iv = window.setInterval(async () => {
463	      const now = itemsRef.current;
464	      const toPoll = now.filter(
465	        (it) => it.phase === "processing" && it.uploadId,
466	      );
467	
468	      // All items terminal? Stop.
469	      if (
470	        toPoll.length === 0 &&
471	        now.length > 0 &&
472	        now.every((it) => itemIsTerminal(it.phase))
473	      ) {
474	        window.clearInterval(iv);
475	        setUploading(false);
476	        const good = now.filter((it) => it.phase === "ingested").length;
477	        const bad = now.filter((it) => it.phase === "failed").length;
478	        if (bad === 0) {
479	          const totalClaims = now.reduce(
480	            (n, it) => n + (it.claimsCount ?? 0),
481	            0,
482	          );
483	          setSuccess(
484	            good === 1
485	              ? `Ingest complete — ${totalClaims} claim(s) extracted. Redirecting…`
486	              : `All ${good} contributions ingested — ${totalClaims} claim(s) total. Redirecting…`,
487	          );
488	          // Auto-redirect on clean runs, same as the pre-bulk UX.
489	          window.setTimeout(() => router.push("/dashboard"), 2600);
490	        } else if (good === 0) {
491	          setError(
492	            `All ${bad} upload(s) failed. See per-file errors below.`,
493	          );
494	          setSuccess("");
495	        } else {
496	          setSuccess(
497	            `${good} ingested, ${bad} failed. Check the errors below; succeeded uploads are already in /library.`,
498	          );
499	        }
500	        return;
501	      }
502	
503	      // Poll each processing item in parallel.
504	      await Promise.all(
505	        toPoll.map(async (it) => {
506	          try {
507	            const pr = await fetch(`/api/upload/${it.uploadId}`);
508	            if (!pr.ok) return;
509	            const u = (await pr.json()) as {
510	              status?: string;
511	              errorMessage?: string | null;
512	              claimsCount?: number;
513	              publicUrl?: string | null;
514	            };
515	            const patch: Partial<UploadItem> = { serverStatus: u.status };
516	            if (u.status === "ingested") {
517	              patch.phase = "ingested";
518	              patch.claimsCount = u.claimsCount ?? 0;
519	              if (u.publicUrl) patch.publicUrl = u.publicUrl;
520	            } else if (u.status === "failed") {
521	              patch.phase = "failed";
522	              patch.errorMessage =
523	                u.errorMessage || "Noosphere reported failure";
524	            }
525	            updateItem(it.id, patch);
526	          } catch {
527	            // Non-fatal; keep polling.
528	          }
529	        }),
530	      );
531	    }, 2000);
532	
533	    // Hard cap — 15 min for a batch; individual workflow timeout is
534	    // 25 min but the user shouldn't watch a spinner that long.
535	    const hardStop = window.setTimeout(() => {
536	      window.clearInterval(iv);
537	      setUploading(false);
538	    }, 900_000);
539	
540	    return () => {
541	      window.clearInterval(iv);
542	      window.clearTimeout(hardStop);
543	    };
544	  }, [uploading, router, updateItem]);
