1	/**
2	 * POST /api/upload/:id/retry — reset a failed upload to `pending`.
3	 *
4	 * The retry button in the dashboard detail row calls this. We
5	 * deliberately keep it narrow:
6	 *
7	 *   * Only rows in `status='failed'` may be retried. Retrying
8	 *     `processing` or `extracting` would race the noosphere runner
9	 *     and could produce duplicate Conclusions (the Wave-0 bug).
10	 *   * We ONLY flip the status + clear the error/extraction fields;
11	 *     we don't trigger a dispatch from here. The local runner and the
12	 *     GitHub Actions cron both sweep `status='pending'` on their own
13	 *     cycles, so the row gets picked up within ~10 minutes at worst
14	 *     without risking a double-dispatch.
15	 *   * Viewers can read but not retry — `canWrite` gate.
16	 *
17	 * Returns `{ ok: true, id }` on success. Non-`failed` statuses give
18	 * 409 with `currentStatus` so the client can show a precise message.
19	 */
20	import { NextResponse } from "next/server";
21	import type { NextRequest } from "next/server";
22	import { getFounderFromAuth } from "@/lib/apiKeyAuth";
23	import { db } from "@/lib/db";
24	import { founderDisplayName } from "@/lib/founderDisplay";
25	import { canWrite, WRITE_FORBIDDEN_RESPONSE } from "@/lib/roles";
26	import { sanitizeAndCap } from "@/lib/sanitizeText";
27	
28	export async function POST(
29	  req: NextRequest,
30	  { params }: { params: Promise<{ id: string }> },
31	) {
32	  const founder = await getFounderFromAuth(req);
33	  if (!founder) {
34	    return NextResponse.json({ error: "Not authenticated" }, { status: 401 });
35	  }
36	  if (!canWrite(founder.role)) {
37	    return NextResponse.json(WRITE_FORBIDDEN_RESPONSE, { status: 403 });
38	  }
39	
40	  const { id } = await params;
41	
42	  const upload = await db.upload.findUnique({
43	    where: { id },
44	    select: {
45	      id: true,
46	      organizationId: true,
47	      founderId: true,
48	      status: true,
49	      deletedAt: true,
50	      visibility: true,
51	      processLog: true,
52	    },
53	  });
54	  if (!upload || upload.deletedAt) {
55	    return NextResponse.json({ error: "Upload not found" }, { status: 404 });
56	  }
57	  if (upload.organizationId !== founder.organizationId) {
58	    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
59	  }
60	  // Private rows stay private to their owner even under retry — an
61	  // admin in the org can't reset someone else's private upload.
62	  if (upload.visibility === "private" && upload.founderId !== founder.id) {
63	    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
64	  }
65	  if (upload.status !== "failed") {
66	    return NextResponse.json(
67	      {
68	        error: "Only failed uploads can be retried.",
69	        currentStatus: upload.status,
70	      },
71	      { status: 409 },
72	    );
73	  }
