/**
 * POST /api/upload/:id/retry — reset a failed upload to `pending`.
 *
 * The retry button in the dashboard detail row calls this. We
 * deliberately keep it narrow:
 *
 *   * Only rows in `status='failed'` may be retried. Retrying
 *     `processing` or `extracting` would race the noosphere runner
 *     and could produce duplicate Conclusions (the Wave-0 bug).
 *   * We ONLY flip the status + clear the error/extraction fields;
 *     we don't trigger a dispatch from here. The local runner and the
 *     GitHub Actions cron both sweep `status='pending'` on their own
 *     cycles, so the row gets picked up within ~10 minutes at worst
 *     without risking a double-dispatch.
 *   * Viewers can read but not retry — `canWrite` gate.
 *
 * Returns `{ ok: true, id }` on success. Non-`failed` statuses give
 * 409 with `currentStatus` so the client can show a precise message.
 */
import { NextResponse } from "next/server";
import type { NextRequest } from "next/server";
import { getFounderFromAuth } from "@/lib/apiKeyAuth";
import { db } from "@/lib/db";
import { founderDisplayName } from "@/lib/founderDisplay";
import { canWrite, WRITE_FORBIDDEN_RESPONSE } from "@/lib/roles";
import { sanitizeAndCap } from "@/lib/sanitizeText";

export async function POST(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> },
) {
  const founder = await getFounderFromAuth(req);
  if (!founder) {
    return NextResponse.json({ error: "Not authenticated" }, { status: 401 });
  }
  if (!canWrite(founder.role)) {
    return NextResponse.json(WRITE_FORBIDDEN_RESPONSE, { status: 403 });
  }

  const { id } = await params;

  const upload = await db.upload.findUnique({
    where: { id },
    select: {
      id: true,
      organizationId: true,
      founderId: true,
      status: true,
      deletedAt: true,
      visibility: true,
      processLog: true,
    },
  });
  if (!upload || upload.deletedAt) {
    return NextResponse.json({ error: "Upload not found" }, { status: 404 });
  }
  if (upload.organizationId !== founder.organizationId) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
  }
  // Private rows stay private to their owner even under retry — an
  // admin in the org can't reset someone else's private upload.
  if (upload.visibility === "private" && upload.founderId !== founder.id) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
  }
  if (upload.status !== "failed") {
    return NextResponse.json(
      {
        error: "Only failed uploads can be retried.",
        currentStatus: upload.status,
      },
      { status: 409 },
    );
  }

  const retryNote = `\n— Retry requested by ${founderDisplayName(founder)} at ${new Date().toISOString()} —\n`;
  await db.upload.update({
    where: { id },
    data: {
      status: "pending",
      errorMessage: null,
      extractionMethod: null,
      // Preserve the previous run's log so the founder can still read
      // what went wrong. The noosphere runner appends on top of this on
      // its next cycle.
      processLog: sanitizeAndCap(upload.processLog + retryNote, 8_000),
    },
  });

  await db.auditEvent.create({
    data: {
      organizationId: founder.organizationId,
      founderId: founder.id,
      uploadId: id,
      action: "upload.retry",
      detail: "Reset failed upload to pending; awaiting noosphere pickup.",
    },
  });

  return NextResponse.json({ ok: true, id });
}

/**
 * Canonical vocabulary for `Upload.status`.
 *
 * The four original values — `pending | processing | ingested | failed`
 * — are load-bearing strings from the init migration. Everything that
 * ever wrote to `Upload.status` (the POST /api/upload handler, the
 * trigger-processing dispatcher, every branch of
 * noosphere/codex_bridge.py, the library filter dropdown) agrees on
 * them. DO NOT rename.
 *
 * The two new values (`extracting`, `awaiting_ingest`) were added in
 * Wave 1 so founders can see which stage of the pipeline their upload
 * is in:
 *
 *   pending          → queued, the local noosphere runner hasn't
 *                      picked it up yet
 *   extracting       → transcribing audio / extracting PDF text; no
 *                      LLM calls in this stage
 *   awaiting_ingest  → text is ready, about to hand off to claim
 *                      extraction
 *   processing       → claim extraction in progress (may call the LLM)
 *   ingested         → conclusions written to the Codex
 *   failed           → see `errorMessage`; retryable from the dashboard
 *
 * The legacy `queued_offline` value (older self-hosted flow where no
 * GitHub Actions dispatch was configured) is intentionally NOT in the
 * list — it's equivalent to `pending` for display purposes and gets
 * treated as such via {@link normalizeStatus}.
 */

export const UPLOAD_STATUSES = [
  "pending",
  "extracting",
  "awaiting_ingest",
  "processing",
  "ingested",
  "failed",
] as const;
export type UploadStatus = (typeof UPLOAD_STATUSES)[number];

export const STATUS_LABEL: Record<UploadStatus, string> = {
  pending: "queued",
  extracting: "extracting text",
  awaiting_ingest: "awaiting ingest",
  processing: "extracting claims",
  ingested: "ingested",
  failed: "failed",
};

export const STATUS_COLOR: Record<UploadStatus, string> = {
  // Muted parchment — the row has arrived but the pipeline hasn't
  // touched it yet. Using a CSS var so the pill adapts to theme swaps.
  pending: "var(--parchment-dim, #8a8675)",
  // Amber family — active, non-terminal, all three stages share the
  // colour so the founder reads "the pipeline is working" without
  // tracking which specific stage we're in.
  extracting: "var(--amber, #c9944a)",
  awaiting_ingest: "var(--amber, #c9944a)",
  processing: "var(--amber, #c9944a)",
  // Moss green — terminal success.
  ingested: "#497a3d",
  // Ember red — terminal failure; matches the existing --ember token.
  failed: "var(--ember, #b33a2a)",
};

export const STATUS_TOOLTIP: Record<UploadStatus, string> = {
  pending: "Waiting for the local noosphere runner to pick this up.",
  extracting: "Transcribing audio or extracting PDF text. No LLM calls yet.",
  awaiting_ingest: "Text is ready; waiting for claim extraction to start.",
  processing: "Claim extraction in progress (may call the LLM).",
  ingested: "Conclusions have been written to your Codex.",
  failed: "Processing failed. See the error detail and retry.",
};

/**
 * Non-terminal statuses animate in the UI so the founder has a visible
 * "pipeline is alive" cue. Excludes `pending` because a row can sit in
 * `pending` for a while (GitHub Actions queue depth, local runner
 * cadence) and a pulse there would imply more activity than is
 * actually happening.
 */
export const PULSING_STATUSES: ReadonlySet<UploadStatus> = new Set<UploadStatus>([
  "extracting",
  "awaiting_ingest",
  "processing",
]);

export function isUploadStatus(s: string): s is UploadStatus {
  return (UPLOAD_STATUSES as readonly string[]).includes(s);
}

/**
 * Map legacy / unknown status strings to a known UploadStatus. Anything
 * not in the canonical list falls back to `pending` so the badge still
 * renders (the founder sees "queued" rather than a raw / blank pill).
 */
export function normalizeStatus(raw: string | null | undefined): UploadStatus {
  if (!raw) return "pending";
  if (isUploadStatus(raw)) return raw;
  if (raw === "queued_offline") return "pending";
  return "pending";
}

enum CitationVerdictLabel {
  ENTAILS
  CONTRADICTS
  NEUTRAL
  AMBIGUOUS
}

model CitationVerdict {
  id             String @id @default(cuid())
  organizationId String

  /// One of "opinion" (OpinionCitation), "forecast" (ForecastCitation),
  /// or "conclusion_source" (ConclusionSource). Not a hard FK because
  /// the three citation tables have different keys.
  citationKind String
  /// Foreign id within `citationKind`. Composite-keyed citation rows
  /// (ConclusionSource: conclusionId+uploadId) encode as
  /// "conclusionId:uploadId".
  citationId String

  /// Canonical source id — matches SourceStanding.sourceId.
  sourceId String

  relation      CitationRelation
  relationHolds CitationVerdictLabel
  confidence    Float

  /// Excerpt actually fed to the NLI judge — recorded verbatim.
  excerptUsed String @db.Text
  /// Firm's stated claim about the source (the hypothesis side of NLI).
  statedClaim String @db.Text

  /// Identifier for the NLI head used to compute this verdict.
  /// Re-running with a different head produces a new row rather than
  /// updating the old one.
  modelVersion String

  /// Cascade load-bearing weight at validation time. Drives the
  /// ambiguous-verdict triage threshold; not used by publication gate.
  cascadeWeight Float @default(0.0)

  /// Founder override — populated when the founder confirmed the
  /// verdict from triage and accepted publication anyway.
  overriddenById String?
  overrideReason String?
  overriddenAt   DateTime?

  /// Raw NLI probability triple, JSON-encoded for forward compat.
  rawPayload Json?

  computedAt DateTime @default(now())
  createdAt  DateTime @default(now())

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId, sourceId])
  @@index([organizationId, citationKind, citationId, computedAt])
  @@index([organizationId, relationHolds, computedAt])
  @@index([sourceId, computedAt])
}

// ── AttentionAction — founder-side snooze/dismiss audit log ──────────────
//
// Append-only ledger of actions a founder has taken on items in the
// unified attention queue surfaced on the dashboard. The queue itself
// is computed at request time from many backing tables (DriftEvent,
// PublicResponse, ResponseTriage, SourceTriageItem, CitationVerdict,
// Contradiction, OpenQuestion, ConclusionDeletionRequest, …); this
// table records the *founder-side* state for each surfaced item:
//
//   * action="snooze"   — hide until snoozedUntil. Snooze windows are
//                          capped at 14 days at the API layer; longer
//                          requests are rewritten as "dismiss" with
//                          reason="deferred indefinitely".
//   * action="dismiss"  — hide indefinitely; reason is required.
//   * action="unsnooze" — explicit re-surface (cancels a prior snooze).
//
// We keep history rather than upserting because a high rate of
// dismissals on a particular queue is itself a signal that the queue
// needs tuning. The current state of an item is the latest row for

  // ── Provenance back-refs ─────────────────────────────────────────
  // Derived entities (Conclusions via the M:N join, Contradictions,
  // OpenQuestions, ResearchSuggestions directly) point back here so
  // the delete path can cascade-clean any artifact whose source has
  // been removed. `conclusionSources` is the many-to-many bridge —
  // the same text can be extracted from multiple uploads, and each
  // upload holds its own row in the bridge. The direct sourceUpload
  // relations on the other three entities are one-per-row: a
  // contradiction / open-question / research suggestion is an output
  // of exactly one ingestion run, even when it references claims from
  // multiple uploads.
  conclusionSources   ConclusionSource[]
  methodologyProfiles MethodologyProfile[]
  contradictions      Contradiction[]      @relation("ContradictionSourceUpload")
  openQuestions       OpenQuestion[]       @relation("OpenQuestionSourceUpload")
  researchSuggestions ResearchSuggestion[] @relation("ResearchSuggestionSourceUpload")

  @@index([organizationId])
  @@index([founderId])
  @@index([publishedAt])
  @@index([deletedAt])
  @@index([visibility])
  // Dashboard filters by status constantly (ingested rows on the main
  // panel, failed/pending counts on the banner). A plain btree index
  // is enough — the org-scope is already covered by organizationId.
  @@index([status])
}

model UploadChunk {
  id           String   @id @default(cuid())
  uploadId     String
  index        Int
  text         String
  startMs      Int?
  endMs        Int?
  speakerLabel String?
  headingHint  String?
  createdAt    DateTime @default(now())
  updatedAt    DateTime @updatedAt

  upload Upload @relation(fields: [uploadId], references: [id], onDelete: Cascade)

  @@unique([uploadId, index])
  @@index([uploadId])
}

// ── DeletionRequest ───────────────────────────────────────────────────
// Peer-to-peer "please delete this" workflow. A founder who doesn't own
// an upload but wants it removed opens a request against that upload;
// the owner reviews it (accept → soft-delete the upload, decline → log
// reason and keep). The requester can cancel their own request at any
// time before the owner responds.
//
// Enforcement:
//   * Requester.organizationId must equal Upload.organizationId (done
//     at route-handler level, not schema — cross-org requests are
//     structurally unreachable via UI anyway).
//   * Requester.id MUST NOT equal Upload.founderId (an owner deletes
//     their own upload directly via DELETE /api/uploads/:id; opening
//     a request against yourself is noise).
//   * At most one ACTIVE (status=pending) request per (upload, requester)
//     pair — the unique partial-index is added in the migration SQL.

model DeletionRequest {
  id          String    @id @default(cuid())
  uploadId    String
  requesterId String
  status      String    @default("pending") // pending | accepted | declined | cancelled
  reason      String?
  decision    String? // optional note from the owner when accepting/declining
  createdAt   DateTime  @default(now())
  respondedAt DateTime?

  upload    Upload  @relation(fields: [uploadId], references: [id], onDelete: Cascade)
  requester Founder @relation(fields: [requesterId], references: [id])

  @@index([uploadId])
  @@index([requesterId])
  @@index([status])
}

// ── Conclusion — mirrors noosphere.models.Conclusion ───────────────────────

model Conclusion {
  id             String @id @default(cuid())
  organizationId String

  /// Stable id if synced from / produced for Noosphere
  noosphereId String? @unique
  text        String

