                style={{
                  fontFamily: "'EB Garamond', serif",
                  fontSize: "0.92rem",
                  color: "var(--parchment-dim)",
                  lineHeight: 1.5,
                }}
              >
                {`Make ${
                  isBulk ? "each upload" : "this upload"
                } visible on `}
                <code
                  className="mono"
                  style={{ fontSize: "0.78rem", color: "var(--amber-dim)" }}
                >
                  /
                </code>
                {" and at "}
                <code
                  className="mono"
                  style={{ fontSize: "0.78rem", color: "var(--amber-dim)" }}
                >
                  /post/&lt;slug&gt;
                </code>
                {`. The Codex itself (conclusions, contradictions, review queue) stays private. You can toggle this later from the dashboard.${
                  isBulk ? " Each file gets its own post." : ""
                }`}
              </span>
            </span>
          </label>

          {publishAsPost && (
            <div
              style={{
                marginTop: "1rem",
                display: "flex",
                flexDirection: "column",
                gap: "0.8rem",
              }}
            >
              <div>
                <label
                  className="mono"
                  style={{
                    fontSize: "0.62rem",
                    letterSpacing: "0.2em",
                    textTransform: "uppercase",
                    color: "var(--amber-dim)",
                    display: "block",
                    marginBottom: "0.3rem",
                  }}
                >
                  {isBulk
                    ? "Shared excerpt (optional — same for every post)"
                    : "Excerpt (optional — shown on index card)"}
                </label>
                <textarea
                  value={blogExcerpt}
                  onChange={(e) => setBlogExcerpt(e.target.value)}
                  rows={2}
                  maxLength={400}
                  placeholder="One or two sentences that make a reader want to click in."
                />
              </div>
              <div>
                <label
                  className="mono"
                  style={{
                    fontSize: "0.62rem",
                    letterSpacing: "0.2em",
                    textTransform: "uppercase",
                    color: "var(--amber-dim)",
                    display: "block",
                    marginBottom: "0.3rem",
                  }}
                >
                  Byline (optional — defaults to your founder name)
                </label>
                <input
                  type="text"
                  value={authorBio}
                  onChange={(e) => setAuthorBio(e.target.value)}
                  maxLength={160}
                  placeholder="e.g. Host and guest, July 2026 · podcast ep. 14"
                />
              </div>
            </div>
          )}
        </div>

        {error && (
          <p style={{ color: "var(--ember)", fontSize: "0.9rem" }}>{error}</p>
        )}
        {success && (
          <p
            style={{
              color: success.startsWith("Failed")
                ? "var(--ember)"
                : "var(--success)",
              fontSize: "0.9rem",
            }}
          >
            {success}
          </p>
        )}
        {items.some((it) => it.phase === "processing") && (
          <div
            role="status"
            aria-live="polite"
            style={{
              marginTop: "0.5rem",
              padding: "0.7rem 0.9rem",
              border: "1px solid var(--amber-dim)",
              borderLeft: "3px solid var(--amber)",
              borderRadius: 2,
              background: "rgba(212,160,23,0.04)",
              fontSize: "0.82rem",
              lineHeight: 1.5,
              color: "var(--parchment)",
            }}
          >
            <span
              className="mono"
              style={{
                display: "block",
                fontSize: "0.6rem",
                letterSpacing: "0.22em",
                textTransform: "uppercase",
                color: "var(--amber-dim)",
                marginBottom: "0.3rem",
              }}
            >
              Safe to leave this page
            </span>
            Noosphere keeps processing in the cloud whether or not this
            tab stays open. Track progress on the{" "}
            <Link href="/knowledge?tab=library" style={{ color: "var(--gold)" }}>
              library
            </Link>{" "}
            or{" "}
            <Link href="/dashboard" style={{ color: "var(--gold)" }}>
              dashboard
            </Link>
            ; you&apos;ll see the row flip from <em>processing</em> to{" "}
            <em>ingested</em> (or <em>failed</em>) when it&apos;s done.
          </div>
        )}

        {hasItems && !committing && !items.some((it) => it.phase === "processing") && (
          <div
            style={{
              padding: "0.7rem 0.9rem",
              border: "1px solid var(--border)",
              borderLeft: "2px solid var(--amber-dim)",
              borderRadius: 2,
              background: "rgba(212,160,23,0.025)",
            }}
          >
            <p
              className="mono"
              style={{
                fontSize: "0.6rem",
                letterSpacing: "0.2em",
                textTransform: "uppercase",
                color: "var(--amber-dim)",
                margin: 0,
              }}
            >
              What happens after upload
            </p>
            <ol
              style={{
                margin: "0.45rem 0 0 1.1rem",
                padding: 0,
                fontSize: "0.82rem",
                lineHeight: 1.55,
                color: "var(--parchment-dim)",
              }}
            >
              <li>File lands in cloud storage.</li>
              <li>
                Extraction or transcription runs (PDF text, DOCX, or audio
                via Whisper).
              </li>
              <li>
                Noosphere analyses the text for claims, contradictions, and
                open questions.
              </li>
              <li>Embeddings are produced for the semantic explorer.</li>
              <li>
                Row flips to <em>ingested</em> on success, or <em>failed</em>{" "}
                with a retry link if a stage breaks.
              </li>
            </ol>
          </div>
        )}

        <button
          type="submit"
          className="btn-solid btn"
          disabled={committing || !hasItems}
        >
          {commitLabel}
        </button>
      </form>
    </main>
  );
}

